const message = ($json.body?.message || '').toLowerCase();
const topic = message.includes('refund') || message.includes('billing') || message.includes('invoice') ? 'billing' : message.includes('login') || message.includes('error') || message.includes('bug') ? 'technical' : 'general';
const urgency = message.includes('urgent') || message.includes('angry') || message.includes('blocked') ? 'high' : message.includes('cannot') || message.includes('failed') ? 'medium' : 'low';
return [{ json: { ...$json.body, classification: { agent: 'intake-classifier', topic, urgency } } }];

const message = ($json.message || '').toLowerCase();
const negativeWords = ['angry', 'frustrated', 'terrible', 'worst', 'fraud'];
const negativeScore = negativeWords.filter((word) => message.includes(word)).length;
return [{ json: { ...$json, sentiment: { agent: 'sentiment-analyzer', label: negativeScore > 0 ? 'negative' : 'neutral', highlyNegative: negativeScore >= 2 } } }];

const message = ($json.message || '').toLowerCase();
const faqs = [
  { id: 'billing-refund', topic: 'billing', keywords: ['refund', 'charged', 'invoice', 'billing'], answer: 'Please share your order ID and charge date so billing can review your refund request.' },
  { id: 'technical-login', topic: 'technical', keywords: ['login', 'password', 'otp'], answer: 'Try resetting your password and confirm whether OTP reaches your registered email or phone.' },
  { id: 'general-hours', topic: 'general', keywords: ['hours', 'contact'], answer: 'Support is available Monday to Friday, 9 AM to 6 PM.' }
];
const match = faqs.find((faq) => faq.topic === $json.classification.topic && faq.keywords.some((keyword) => message.includes(keyword)));
return [{ json: { ...$json, faq: { agent: 'faq-responder', matched: Boolean(match), faqId: match?.id || null, response: match?.answer || 'No exact FAQ match found.' } } }];
